import React, { useState, useEffect } from 'react';
import { Table, Button } from 'react-bootstrap';
import { Link } from 'react-router-dom';
import { getCategories, getProducts, removeProduct } from '../config/api';

function ListProduct() {
    const [products, setProducts] = useState([]);
    const [categories, setCategories] = useState([]);

    // Hàm load dữ liệu từ API
    const loadData = async () => {
        try {
            const res1 = await getProducts();
            setProducts(res1.data);
            const res2 = await getCategories();
            setCategories(res2.data);
        } catch (error) {
            console.error("Lỗi khi lấy dữ liệu:", error);
        }
    }; // <-- Đã đóng ngoặc nhọn hàm loadData ở đây

    useEffect(() => {
        loadData(); // <-- Gọi đúng hàm loadData khi component mount
    }, []);

    // Hàm xử lý khi bấm xóa sản phẩm
    const handleDelete = async (id) => {
        if (window.confirm("Bạn có chắc chắn muốn xóa sản phẩm này không?")) {

                await removeProduct(id);
                loadData(); }// <-- Load lại dữ liệu mới sau khi xóa thành công

    };

    const getCategoryName = (categoryId) => {
        const category = categories.find((c) => c.id === categoryId);
        return category ? category.name : "NoName";
    };
    const deleteProduct = async (id) => {
        if(window.confirm("Are you sure you want to delete id= " + id + "?" )){

                await removeProduct(id);
                loadData(); 
            }
        }

    return (
        <div>
            <h2 className='mt-4'>List of Products</h2>
            <Link to='/add'>
                <Button variant='primary' className='mt-3'>Add Product</Button>
            </Link>
            <Table bordered striped className="mt-3">
                <thead>
                    <tr> {/* <-- Thêm thẻ tr ở đây */}
                        <th>ID</th>
                        <th>Images</th>
                        <th>Name</th>
                        <th>Price</th>
                        <th>Category</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    {products?.map((p) => (
                        <tr key={p.id}>
                            <td>{p.id}</td>
                            <td><img src={p.Images} alt={p.Name} style={{ width: '100px' }} /></td>
                            <td>{p.Name}</td>
                            <td>${p.Price ? p.Price.toFixed(2) : "0.00"}</td> {/* Tránh lỗi nếu Price bị undefined */}
                            <td>{getCategoryName(p.Category_ID)}</td>
                            <td>
                                <Link to={`/edit/${p.id}`}>
                                    <Button variant="warning" className="me-2">Edit</Button>
                                </Link>

                                <Button variant="danger" onClick={() => handleDelete(p.id)}>Delete</Button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </Table>
        </div>
    );
}

export default ListProduct;
